127→                        isLast={index === conversations.length - 1}
128→                      />
129→                      {!isInherited && conversation.response && onboardingState === "complete" ? (
130→                        <button
131→                          type="button"
132→                          className="branch-message-btn"
133→                          onClick={() => void chat.onBranchFromMessage(conversation.id)}
134→                          disabled={chat.isLoading || chat.branchingFromId !== undefined}
135→                          title="Branch from here"
136→                        >
137→                          <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
138→                            <path d="M5 3v4.5c0 1.1.9 2 2 2h2.5M5 3L3 5M5 3l2 2M11 5v4.5c0 1.1-.9 2-2 2H6.5M11 5l-2-2M11 5l2-2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
139→                          </svg>
140→                        </button>
141→                      ) : undefined}
