  1→import { MouseEvent, useEffect, useMemo, useRef, useState } from "react";
  2→import type {
  3→  Session,
  4→  Suggestion,
  5→  MentionItem,
  6→  ChatInputRef,
  7→} from "reachat";
  8→import type {
  9→  BranchConversationResponse,
 10→  ChatMessageResponse,
 11→  OnboardingAction,
 12→  SearchEntityResponse,
 13→  StreamEvent as ChatStreamEvent,
 14→  WorkspaceConversationResponse,
 15→} from "../../shared/contracts";
 16→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 17→import { useViewState } from "../stores/view-state";
 18→
 19→type UseChatSessionReturn = {
 20→  sessions: Session[];
 21→  activeSessionId: string;
 22→  activeSession: Session;
 23→  activeConversationId?: string;
 24→  isLoading: boolean;
 25→  errorMessage?: string;
 26→  suggestions: Suggestion[];
 27→  pendingFile?: File;
 28→  branchingFromId?: string;
 29→  inheritedMessageIds: Set<string>;
 30→  chatInputRef: React.RefObject<ChatInputRef | null>;
 31→  onSendMessage: (message: string, options?: { onboardingAction?: OnboardingAction }) => Promise<void>;
 32→  onStopMessage: () => void;
 33→  onNewConversation: () => void;
 34→  onSelectConversation: (conversationId: string) => void;
 35→  onBranchFromMessage: (messageId: string) => Promise<void>;
 36→  searchMentions: (query: string) => Promise<MentionItem[]>;
 37→  onUploadFile: (file: File) => void;
 38→  onChatInputClickCapture: (event: MouseEvent<HTMLDivElement>) => void;
 39→  setErrorMessage: (message: string | undefined) => void;
 40→  refreshSidebar: (workspaceId: string) => Promise<void>;
 41→};
 42→
 43→export function useChatSession(): UseChatSessionReturn {
 44→  const store = useWorkspaceState();
 45→  const workspaceId = store.workspaceId;
 46→  const workspaceName = store.workspaceName;
 47→  const bootstrapPayload = store.bootstrapPayload;
 48→
 49→  const [sessions, setSessions] = useState<Session[]>([
 50→    {
 51→      id: "main",
 52→      title: "Workspace Chat",
 53→      createdAt: new Date(),
 54→      updatedAt: new Date(),
 55→      conversations: [],
 56→    },
 57→  ]);
 58→  const [activeSessionId] = useState("main");
 59→  const [backendConversationId, setBackendConversationId] = useState<string | undefined>();
 60→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 61→  const [isLoading, setIsLoading] = useState(false);
 62→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 63→  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
 64→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 65→  const [inheritedMessageIds, setInheritedMessageIds] = useState<Set<string>>(new Set());
 66→  const [pendingFile, setPendingFile] = useState<File | undefined>();
 67→  const streamRef = useRef<EventSource | undefined>(undefined);
 68→  const chatInputRef = useRef<ChatInputRef | null>(null);
 69→
 70→  // Track the last applied bootstrap payload to avoid re-applying
 71→  const appliedBootstrapRef = useRef<BootstrapPayload | undefined>(undefined);
 72→
 73→  const activeSession = useMemo(
 74→    () => sessions.find((session) => session.id === activeSessionId),
 75→    [sessions, activeSessionId],
 76→  );
 77→
 78→  if (!activeSession) {
 79→    throw new Error("active session missing");
 80→  }
 81→
 82→  // Apply bootstrap payload when it arrives
 83→  useEffect(() => {
 84→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
 85→      return;
 86→    }
 87→    appliedBootstrapRef.current = bootstrapPayload;
 88→
 89→    setSessions([
 90→      {
 91→        id: "main",
 92→        title: workspaceName ?? "Workspace Chat",
 93→        createdAt: new Date(),
 94→        updatedAt: new Date(),
 95→        conversations: bootstrapPayload.conversations,
 96→      },
 97→    ]);
 98→    setInheritedMessageIds(bootstrapPayload.inheritedIds);
 99→    setSuggestions(
100→      bootstrapPayload.latestSuggestions.map((content, index) => ({
101→        id: `bootstrap-suggestion-${index}-${content}`,
102→        content,
103→      })),
104→    );
105→    setActiveConversationId(store.conversationId);
106→    setBackendConversationId(store.conversationId);
107→  }, [bootstrapPayload]);
108→
109→  // Highlight message support (graph -> chat navigation)
110→  const highlightMessageId = useViewState((s) => s.highlightMessageId);
111→  const clearHighlight = useViewState((s) => s.clearHighlight);
112→
113→  useEffect(() => {
114→    if (!highlightMessageId) return;
115→
116→    const timer = setTimeout(() => {
117→      const element = document.querySelector(`[data-message-id="${highlightMessageId}"]`);
118→      if (element) {
119→        element.scrollIntoView({ behavior: "smooth", block: "center" });
120→        element.classList.add("animate-highlight");
121→        element.addEventListener(
122→          "animationend",
123→          () => {
124→            element.classList.remove("animate-highlight");
125→          },
126→          { once: true },
127→        );
128→      }
129→      clearHighlight();
130→    }, 100);
131→
132→    return () => clearTimeout(timer);
133→  }, [highlightMessageId, clearHighlight]);
134→
135→  async function refreshSidebar(wsId: string) {
136→    try {
137→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
138→      if (response.ok) {
139→        const payload = await response.json();
140→        store.setSidebar(payload);
141→      }
142→    } catch {
143→      // Sidebar refresh is non-critical; silently ignore
144→    }
145→  }
146→
147→  async function loadConversation(wsId: string, conversationId: string) {
148→    try {
149→      const response = await fetch(
150→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
151→      );
152→      if (!response.ok) {
153→        const body = await response.text();
154→        setErrorMessage(body);
155→        return;
156→      }
157→
158→      const payload = (await response.json()) as WorkspaceConversationResponse;
159→      const conversations: Session["conversations"] = [];
160→      let latestSuggestions: string[] = [];
161→      const inheritedIds = new Set<string>();
162→
163→      for (const message of payload.messages) {
164→        if (message.role === "user") {
165→          conversations.push({
166→            id: message.id,
167→            question: message.text,
168→            createdAt: new Date(message.createdAt),
169→          });
170→          if (message.inherited) {
171→            inheritedIds.add(message.id);
172→          }
173→          continue;
174→        }
175→
176→        const last = conversations[conversations.length - 1];
177→        if (last && !last.response) {
178→          last.response = message.text;
179→          last.updatedAt = new Date(message.createdAt);
180→          latestSuggestions =
181→            message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
182→          if (message.inherited) {
183→            inheritedIds.add(last.id);
184→          }
185→          continue;
186→        }
187→
188→        conversations.push({
189→          id: `assistant-${message.id}`,
190→          question: "System kickoff",
191→          response: message.text,
192→          createdAt: new Date(message.createdAt),
193→        });
194→        if (message.inherited) {
195→          inheritedIds.add(`assistant-${message.id}`);
196→        }
197→        latestSuggestions =
198→          message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
199→      }
200→
201→      setInheritedMessageIds(inheritedIds);
202→      setSessions([
203→        {
204→          id: "main",
205→          title: workspaceName ?? "Workspace Chat",
206→          createdAt: new Date(),
207→          updatedAt: new Date(),
208→          conversations,
209→        },
210→      ]);
211→
212→      setSuggestions(
213→        latestSuggestions.map((content, index) => ({
214→          id: `conv-suggestion-${index}-${content}`,
215→          content,
216→        })),
217→      );
218→
219→      setActiveConversationId(conversationId);
220→      setBackendConversationId(conversationId);
221→    } catch (error) {
222→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
223→      setErrorMessage(messageText);
224→    }
225→  }
226→
227→  function onNewConversation() {
228→    setActiveConversationId(undefined);
229→    setBackendConversationId(undefined);
230→    setSessions([
231→      {
232→        id: "main",
233→        title: workspaceName ?? "Workspace Chat",
234→        createdAt: new Date(),
235→        updatedAt: new Date(),
236→        conversations: [],
237→      },
238→    ]);
239→    setSuggestions([]);
240→    setErrorMessage(undefined);
241→  }
242→
243→  function onSelectConversation(conversationId: string) {
244→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
245→      return;
246→    }
247→
248→    void loadConversation(workspaceId, conversationId);
249→  }
250→
251→  async function onBranchFromMessage(messageId: string) {
252→    if (!workspaceId || !activeConversationId || isLoading) return;
253→
254→    setBranchingFromId(messageId);
255→    try {
256→      const response = await fetch(
257→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
258→        {
259→          method: "POST",
260→          headers: { "Content-Type": "application/json" },
261→          body: JSON.stringify({ messageId }),
262→        },
263→      );
264→
265→      if (!response.ok) {
266→        const body = await response.text();
267→        setErrorMessage(body);
268→        return;
269→      }
270→
271→      const payload = (await response.json()) as BranchConversationResponse;
272→      await loadConversation(workspaceId, payload.conversationId);
273→      await refreshSidebar(workspaceId);
274→    } catch (error) {
275→      const messageText = error instanceof Error ? error.message : "Branch creation failed";
276→      setErrorMessage(messageText);
277→    } finally {
278→      setBranchingFromId(undefined);
279→    }
280→  }
281→
282→  async function searchMentions(query: string): Promise<MentionItem[]> {
283→    if (!workspaceId) {
284→      return [];
285→    }
286→
287→    const response = await fetch(
288→      `/api/entities/search?q=${encodeURIComponent(query)}&workspaceId=${encodeURIComponent(workspaceId)}&limit=8`,
289→    );
290→    if (!response.ok) {
291→      throw new Error(`entity search failed: ${response.status}`);
292→    }
293→
294→    const rows = (await response.json()) as SearchEntityResponse[];
295→    return rows.map((row) => ({
296→      id: row.id,
297→      label: `${row.kind}: ${row.text.slice(0, 48)}`,
298→      description: `confidence ${row.confidence.toFixed(2)}`,
299→      value: `@${row.id}`,
300→    }));
301→  }
302→
303→  function onUploadFile(file: File) {
304→    setPendingFile(file);
305→  }
306→
307→  function onChatInputClickCapture(event: MouseEvent<HTMLDivElement>) {
308→    if (!pendingFile || isLoading) {
309→      return;
310→    }
311→
312→    const target = event.target;
313→    if (!(target instanceof Element)) {
314→      return;
315→    }
316→
317→    const sendButton = target.closest("button[title='Send']");
318→    if (!sendButton) {
319→      return;
320→    }
321→
322→    const currentMessage = chatInputRef.current?.getValue().trim() ?? "";
323→    if (currentMessage.length > 0) {
324→      return;
325→    }
326→
327→    event.preventDefault();
328→    event.stopPropagation();
329→    void onSendMessage("");
330→  }
331→
332→  async function onSendMessage(
333→    message: string,
334→    options?: { onboardingAction?: OnboardingAction },
335→  ) {
336→    if (isLoading || !workspaceId) {
337→      return;
338→    }
339→
340→    const text = message.trim();
341→    if (!text && !pendingFile) {
342→      return;
343→    }
344→
345→    setErrorMessage(undefined);
346→    setIsLoading(true);
347→    setSuggestions([]);
348→
349→    const clientMessageId = crypto.randomUUID();
350→    const currentAttachment = pendingFile;
351→
352→    setSessions((existing) =>
353→      existing.map((session) =>
354→        session.id === activeSessionId
355→          ? {
356→              ...session,
357→              updatedAt: new Date(),
358→              conversations: [
359→                ...session.conversations,
360→                {
361→                  id: clientMessageId,
362→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
363→                  createdAt: new Date(),
364→                  ...(currentAttachment
365→                    ? {
366→                        files: [
367→                          {
368→                            name: currentAttachment.name,
369→                            type: currentAttachment.type,
370→                            size: currentAttachment.size,
371→                          },
372→                        ],
373→                      }
374→                    : {}),
375→                },
376→              ],
377→            }
378→          : session,
379→      ),
380→    );
381→
382→    let response: Response;
383→    try {
384→      if (currentAttachment) {
385→        const formData = new FormData();
386→        formData.set("clientMessageId", clientMessageId);
387→        formData.set("workspaceId", workspaceId);
388→        formData.set("text", text);
389→        if (backendConversationId) {
390→          formData.set("conversationId", backendConversationId);
391→        }
392→        if (options?.onboardingAction) {
393→          formData.set("onboardingAction", options.onboardingAction);
394→        }
395→        formData.set("file", currentAttachment);
396→
397→        response = await fetch("/api/chat/messages", {
398→          method: "POST",
399→          body: formData,
400→        });
401→      } else {
402→        response = await fetch("/api/chat/messages", {
403→          method: "POST",
404→          headers: {
405→            "Content-Type": "application/json",
406→          },
407→          body: JSON.stringify({
408→            clientMessageId,
409→            workspaceId,
410→            text,
411→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
412→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
413→          }),
414→        });
415→      }
416→    } catch (error) {
417→      const messageText = error instanceof Error ? error.message : "Network error";
418→      setErrorMessage(messageText);
419→      setIsLoading(false);
420→      return;
421→    } finally {
422→      setPendingFile(undefined);
423→    }
424→
425→    if (!response.ok) {
426→      const body = await response.text();
427→      setErrorMessage(body);
428→      setIsLoading(false);
429→      return;
430→    }
431→
432→    const payload = (await response.json()) as ChatMessageResponse;
433→    const isNewConversation = !backendConversationId;
434→    setBackendConversationId(payload.conversationId);
435→    if (isNewConversation) {
436→      setActiveConversationId(payload.conversationId);
437→    }
438→
439→    if (streamRef.current) {
440→      streamRef.current.close();
441→      streamRef.current = undefined;
442→    }
443→
444→    let streamedText = "";
445→
446→    const stream = new EventSource(payload.streamUrl);
447→    streamRef.current = stream;
448→
449→    stream.onmessage = (messageEvent) => {
450→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
451→
452→      if (parsed.type === "token") {
453→        streamedText = `${streamedText}${parsed.token}`;
454→        setSessions((existing) =>
455→          existing.map((session) =>
456→            session.id === activeSessionId
457→              ? {
458→                  ...session,
459→                  conversations: session.conversations.map((conversation) =>
460→                    conversation.id === clientMessageId
461→                      ? {
462→                          ...conversation,
463→                          response: streamedText,
464→                          updatedAt: new Date(),
465→                        }
466→                      : conversation,
467→                  ),
468→                }
469→              : session,
470→          ),
471→        );
472→        return;
473→      }
474→
475→      if (parsed.type === "extraction") {
476→        store.mergeSeedItems(
477→          parsed.entities.map((entity) => ({
478→            id: entity.id,
479→            kind: entity.kind,
480→            text: entity.text,
481→            confidence: entity.confidence,
482→            sourceKind: entity.sourceKind,
483→            sourceId: entity.sourceId,
484→          })),
485→        );
486→        return;
487→      }
488→
489→      if (parsed.type === "assistant_message") {
490→        streamedText = parsed.text;
491→        setSuggestions(
492→          (parsed.suggestions ?? []).map((content, index) => ({
493→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
494→            content,
495→          })),
496→        );
497→        setSessions((existing) =>
498→          existing.map((session) =>
499→            session.id === activeSessionId
500→              ? {
501→                  ...session,
502→                  conversations: session.conversations.map((conversation) =>
503→                    conversation.id === clientMessageId
504→                      ? {
505→                          ...conversation,
506→                          response: streamedText,
507→                          updatedAt: new Date(),
508→                        }
509→                      : conversation,
510→                  ),
511→                }
512→              : session,
513→          ),
514→        );
515→        return;
516→      }
517→
518→      if (parsed.type === "onboarding_seed") {
519→        store.mergeSeedItems(parsed.seeds);
520→        return;
521→      }
522→
523→      if (parsed.type === "onboarding_state") {
524→        store.setOnboardingState(parsed.onboardingState);
525→        return;
526→      }
527→
528→      if (parsed.type === "error") {
529→        setErrorMessage(parsed.error);
530→        setIsLoading(false);
531→        stream.close();
532→        streamRef.current = undefined;
533→        return;
534→      }
535→
536→      if (parsed.type === "done") {
537→        setSessions((existing) =>
538→          existing.map((session) =>
539→            session.id === activeSessionId
540→              ? {
541→                  ...session,
542→                  updatedAt: new Date(),
543→                  conversations: session.conversations.map((conversation) =>
544→                    conversation.id === clientMessageId
545→                      ? {
546→                          ...conversation,
547→                          response: streamedText,
548→                          updatedAt: new Date(),
549→                        }
550→                      : conversation,
551→                  ),
552→                }
553→              : session,
554→          ),
555→        );
556→
557→        setIsLoading(false);
558→        stream.close();
559→        streamRef.current = undefined;
560→
561→        // Refresh sidebar after stream completes
562→        if (workspaceId) {
563→          void refreshSidebar(workspaceId);
564→        }
565→      }
566→    };
567→
568→    stream.onerror = () => {
569→      setErrorMessage("SSE stream disconnected");
570→      setIsLoading(false);
571→      stream.close();
572→      streamRef.current = undefined;
573→    };
574→  }
575→
576→  function onStopMessage() {
577→    if (!streamRef.current) {
578→      return;
579→    }
580→
581→    streamRef.current.close();
582→    streamRef.current = undefined;
583→    setIsLoading(false);
584→  }
585→
586→  return {
587→    sessions,
588→    activeSessionId,
589→    activeSession,
590→    activeConversationId,
591→    isLoading,
592→    errorMessage,
593→    suggestions,
594→    pendingFile,
595→    branchingFromId,
596→    inheritedMessageIds,
597→    chatInputRef,
598→    onSendMessage,
599→    onStopMessage,
600→    onNewConversation,
601→    onSelectConversation,
602→    onBranchFromMessage,
603→    searchMentions,
604→    onUploadFile,
605→    onChatInputClickCapture,
606→    setErrorMessage,
607→    refreshSidebar,
608→  };
609→}
