10→async function executeEntityAction(
11→  workspaceId: string,
12→  entityId: string,
13→  action: string,
14→): Promise<void> {
15→  const response = await fetch(
16→    `/api/entities/${encodeURIComponent(entityId)}/actions?workspaceId=${encodeURIComponent(workspaceId)}`,
17→    {
18→      method: "POST",
19→      headers: { "Content-Type": "application/json" },
20→      body: JSON.stringify({ action }),
