29→export function GovernanceFeed({
30→  feed,
31→  isLoading,
32→  error,
33→  onRefresh,
34→}: {
35→  feed: GovernanceFeedResponse | undefined;
36→  isLoading: boolean;
37→  error: string | undefined;
38→  onRefresh: () => void;
39→}) {
40→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
41→  const navigate = useNavigate();
42→
43→  async function handleAction(item: GovernanceFeedItem, action: GovernanceFeedAction) {
44→    if (!workspaceId) return;
45→
46→    if (action.action === "discuss") {
47→      void navigate({ to: "/chat", search: { discuss: item.entityId } });
48→      return;
49→    }
50→
51→    await executeEntityAction(workspaceId, item.entityId, action.action);
52→    onRefresh();
53→  }
54→
55→  if (error) {
56→    return (
57→      <div className="feed-error">
58→        <p>{error}</p>
59→        <button type="button" onClick={onRefresh}>Retry</button>
60→      </div>
61→    );
62→  }
63→
64→  if (!feed && isLoading) {
65→    return <p className="feed-loading">Loading governance feed...</p>;
66→  }
67→
68→  if (!feed) return undefined;
69→
70→  const totalItems = feed.blocking.length + feed.review.length + feed.awareness.length;
71→
72→  if (totalItems === 0) {
73→    return (
74→      <div className="feed-empty">
75→        <p>No governance items require attention.</p>
76→      </div>
77→    );
78→  }
79→
80→  return (
81→    <div className="governance-feed">
82→      <FeedSection tier="blocking" items={feed.blocking} onAction={handleAction} />
83→      <FeedSection tier="review" items={feed.review} onAction={handleAction} />
84→      <FeedSection tier="awareness" items={feed.awareness} onAction={handleAction} />
85→    </div>
86→  );
87→}
